const body = $('DMS Sync Webhook').first().json.body;
const integration = $('Get DMS Integration').first().json;
const action = body.action;

// Build the DMS API request based on provider and action
const provider = integration.provider;
const apiKey = integration.api_key || '';
const apiUrl = integration.api_url || '';
const shopExternalId = integration.shop_external_id || '';
const oauthToken = integration.oauth_token || '';

// Provider-specific base URLs
const baseUrls = {
  tekmetric: apiUrl || 'https://shop.tekmetric.com/api/v1',
  mitchell1: apiUrl || 'https://api.mitchell1.com/v1',
  shopware: apiUrl || 'https://api.shop-ware.com/api/v1'
};

const baseUrl = baseUrls[provider] || '';

// Auth headers per provider
const authHeaders = {
  tekmetric: { 'Authorization': `Bearer ${oauthToken || apiKey}` },
  mitchell1: { 'X-Api-Key': apiKey },
  shopware: { 'Authorization': `Bearer ${apiKey}` }
};

const headers = {
  ...authHeaders[provider],
  'Content-Type': 'application/json',
  'Accept': 'application/json'
};

let endpoint = '';
let method = 'POST';
let requestBody = {};

switch (action) {
  case 'sync_customer': {
    const caller = body.caller_data || {};
    const nameParts = (caller.name || '').split(' ');
    const firstName = nameParts[0] || 'Unknown';
    const lastName = nameParts.slice(1).join(' ') || '';

    if (provider === 'tekmetric') {
      endpoint = '/customers';
      requestBody = {
        shopId: Number(shopExternalId),
        firstName,
        lastName,
        phone: [{ number: caller.phone, type: 'Mobile' }]
      };
    } else if (provider === 'mitchell1') {
      endpoint = `/shops/${shopExternalId}/customers`;
      requestBody = { shopId: shopExternalId, firstName, lastName, phoneNumber: caller.phone };
    } else if (provider === 'shopware') {
      endpoint = '/customers';
      requestBody = {
        shop_id: Number(shopExternalId),
        first_name: firstName,
        last_name: lastName,
        phone_numbers: [{ number: caller.phone, type: 'mobile' }]
      };
    }
    break;
  }

  case 'sync_vehicle': {
    const v = body.vehicle_data || {};
    const customerId = body.dms_customer_id || '';

    if (provider === 'tekmetric') {
      endpoint = '/vehicles';
      requestBody = { customerId: Number(customerId), year: v.year, make: v.make, model: v.model, vin: v.vin || '' };
    } else if (provider === 'mitchell1') {
      endpoint = `/shops/${shopExternalId}/vehicles`;
      requestBody = { customerId, year: v.year, make: v.make, model: v.model, vin: v.vin || '' };
    } else if (provider === 'shopware') {
      endpoint = '/vehicles';
      requestBody = { customer_id: Number(customerId), year: v.year, make: v.make, model: v.model, vin: v.vin || '' };
    }
    break;
  }

  case 'sync_repair_order': {
    const customerId = body.dms_customer_id || '';
    const vehicleId = body.dms_vehicle_id || '';
    const description = body.issue_summary || '';

    if (provider === 'tekmetric') {
      endpoint = '/repair-orders';
      requestBody = {
        shopId: Number(shopExternalId),
        customerId: Number(customerId),
        vehicleId: Number(vehicleId),
        customerConcern: description
      };
    } else if (provider === 'mitchell1') {
      endpoint = `/shops/${shopExternalId}/jobs`;
      requestBody = { customerId, vehicleId, concern: description, status: 'Estimate' };
    } else if (provider === 'shopware') {
      endpoint = '/repair_orders';
      requestBody = {
        shop_id: Number(shopExternalId),
        customer_id: Number(customerId),
        vehicle_id: Number(vehicleId),
        customer_concern: description,
        state: 'estimate'
      };
    }
    break;
  }

  case 'sync_appointment': {
    const appt = body.appointment_data || {};
    const customerId = body.dms_customer_id || '';
    const vehicleId = body.dms_vehicle_id || '';

    if (provider === 'tekmetric') {
      endpoint = '/appointments';
      requestBody = {
        shopId: Number(shopExternalId),
        customerId: Number(customerId),
        vehicleId: vehicleId ? Number(vehicleId) : undefined,
        startTime: appt.preferred_day + 'T' + (appt.preferred_time || '09:00') + ':00',
        duration: 60,
        note: appt.service_description
      };
    } else if (provider === 'mitchell1') {
      endpoint = `/shops/${shopExternalId}/appointments`;
      requestBody = {
        customerId,
        vehicleId,
        scheduledDateTime: appt.preferred_day + 'T' + (appt.preferred_time || '09:00') + ':00',
        durationMinutes: 60,
        serviceDescription: appt.service_description
      };
    } else if (provider === 'shopware') {
      endpoint = '/appointments';
      requestBody = {
        shop_id: Number(shopExternalId),
        customer_id: Number(customerId),
        vehicle_id: vehicleId ? Number(vehicleId) : undefined,
        start_at: appt.preferred_day + 'T' + (appt.preferred_time || '09:00') + ':00',
        duration_minutes: 60,
        title: appt.service_description
      };
    }
    break;
  }
}

return {
  provider,
  action,
  base_url: baseUrl,
  endpoint,
  method,
  headers,
  body: requestBody,
  full_url: baseUrl + endpoint,
  integration_id: integration.id,
  shop_id: body.shop_id,
  entity_id: body.entity_id || ''
};

const buildReq = $('Build DMS API Request').first().json;
const response = $input.first().json;

// Extract external ID from the response based on provider
let externalId = '';
if (response.id) externalId = String(response.id);
else if (response.customerId) externalId = response.customerId;
else if (response.vehicleId) externalId = response.vehicleId;
else if (response.jobId) externalId = response.jobId;
else if (response.appointmentId) externalId = response.appointmentId;

return {
  status: 'synced',
  external_id: externalId,
  integration_id: buildReq.integration_id,
  shop_id: buildReq.shop_id,
  entity_id: buildReq.entity_id,
  action: buildReq.action,
  provider: buildReq.provider
};

const buildReq = $('Build DMS API Request').first().json;
const error = $input.first().json;

return {
  status: 'failed',
  external_id: '',
  integration_id: buildReq.integration_id,
  shop_id: buildReq.shop_id,
  entity_id: buildReq.entity_id,
  action: buildReq.action,
  provider: buildReq.provider,
  error_message: JSON.stringify(error).substring(0, 500)
};
